//
// Device Settings
package modbus

import (
	"context"

	"github.com/arminguenther/xeruspower-go/v40033/idl"
)

const ERR_INVALID_PARAM int32 = 1 // Invalid parameters

// Modbus service settings interface
type Modbus interface {
	idl.Object

	// Retrieve the device Modbus capabilities.
	//
	//	@return Modbus capbilities
	GetCapabilities(ctx context.Context) (Capabilities, error)

	// Retrieve the Modbus service settings.
	//
	//	@return Modbus service settings
	GetSettings(ctx context.Context) (Settings, error)

	// Set the Modbus service settings.
	//
	//	@param settings New settings
	//
	//	@return 0 if OK
	//	@return 1 if any parameters are invalid
	SetSettings(ctx context.Context, settings Settings) (int32, error)
}

// Device modbus capabilities
type Capabilities struct {
	HasModbusSerial bool // Device has a serial Modbus port
}

// Modbus/TCP settings.
//
//	@note Port number and enabled flag are configured using
//	      net::Net::setNetworkConfigServices.
type TcpSettings struct {
	Readonly bool // Disallow write requests
}

// Serial line parity
type Parity int

const (
	NONE Parity = iota
	EVEN
	ODD
)

// Modbus/serial settings.
type SerialSettings struct {
	Enabled  bool   // Enable the Modbus/RTU service
	Baudrate int32  // Baudrate
	Parity   Parity // Parity
	Stopbits int32  // Number of stop bits (1 or 2)
	Readonly bool   // Disallow write requests
}

// Modbus service settings
type Settings struct {
	Tcp    TcpSettings    // Modbus/TCP settings
	Serial SerialSettings // Modbus/serial settings
	// Main unit ID, 0 to disable
	//
	//	@note Models that act as a simple Modbus device
	//	will ignore this setting for TCP connections and
	//	respond to all unit IDs.
	PrimaryUnitId int32
}
